+            ) {
+                let mut rb = RingBuffer::new(cap);
+                for item in &items {
+                    rb.push(*item);
+                }
+                let expected = items.len().saturating_sub(cap) as u64;
+                prop_assert_eq!(rb.total_evicted(), expected);
+            }
+
+            /// Iteration yields exactly the last min(N, cap) items in order.
